function [7:0] lookup(input [WIDTH-1:0] index);
integer i;
reg [7:0] val_table [DEPTH-1:0];
begin
for(i = 0; i < DEPTH; i = i + 1) begin
val_table[i] = ~(i & 32'hFF);
end
lookup = val_table[index];
end
endfunction

function [7:0] lookup(input select, input [WIDTH-1:0] index);
integer i;
reg [7:0] val_table_a [DEPTH-1:0];
reg [7:0] val_table_b [DEPTH-1:0];
begin
for(i = 0; i < DEPTH; i = i + 1) begin
val_table_a[i] = ~(i & 8'hFF);
val_table_b[i] = ~(i & 8'hF0);
end
lookup = (select) ? val_table_a[index] : val_table_b[index];
end
endfunction
